class Solution:
    def countPyramids(self, grid):
        def count_upright(g):
            m, n = len(g), len(g[0])
            total = 0
            for r in range(m):
                for c in range(n):
                    h = 1
                    while True:
                        nh = h + 1
                        top = r + nh - 1
                        if top >= m:
                            break
                        ok = True
                        for i in range(r, top + 1):
                            spread = i - r
                            lo, hi = c - spread, c + spread
                            if lo < 0 or hi >= n:
                                ok = False
                                break
                            for j in range(lo, hi + 1):
                                if g[i][j] != 1:
                                    ok = False
                                    break
                            if not ok:
                                break
                        if not ok:
                            break
                        h = nh
                        total += 1
            return total
        return count_upright(grid) + count_upright(grid[::-1])

