class Solution:
    def countPyramids(self, grid):
        def count_upright(g):
            m, n = len(g), len(g[0])
            dp = [row[:] for row in g]
            total = 0
            for i in range(m - 2, -1, -1):
                for j in range(n):
                    if dp[i][j] == 0:
                        continue
                    left = dp[i + 1][j - 1] if j - 1 >= 0 else 0
                    right = dp[i + 1][j + 1] if j + 1 < n else 0
                    mid = dp[i + 1][j]
                    dp[i][j] = min(left, mid, right) + 1
                    total += dp[i][j] - 1
            return total
        return count_upright(grid) + count_upright(grid[::-1])

