var countPyramids = function(grid) {
    function countUpright(g) {
        const m = g.length, n = g[0].length;
        const dp = g.map(row => row.slice());
        let total = 0;
        for (let i = m - 2; i >= 0; i--) {
            for (let j = 0; j < n; j++) {
                if (dp[i][j] === 0) continue;
                const left = j - 1 >= 0 ? dp[i + 1][j - 1] : 0;
                const right = j + 1 < n ? dp[i + 1][j + 1] : 0;
                const mid = dp[i + 1][j];
                dp[i][j] = Math.min(left, mid, right) + 1;
                total += dp[i][j] - 1;
            }
        }
        return total;
    }
    const flipped = grid.slice().reverse();
    return countUpright(grid) + countUpright(flipped);
};
